import json
import logging
import re
import boto3
from botocore.exceptions import ClientError

logger = logging.getLogger()
logger.setLevel(logging.INFO)

# Allowlist of permitted SNS topic ARNs - configure these for your environment
ALLOWED_TOPIC_ARNS = set()
ALLOWED_TOPIC_ARN_PATTERN = None

# Configuration: Set your AWS account ID and region for validation
ALLOWED_AWS_ACCOUNT_IDS = set()
ALLOWED_REGIONS = set()

SNS_ARN_PATTERN = re.compile(
    r'^arn:aws:sns:[a-z0-9-]+:\d{12}:[a-zA-Z0-9_-]+$'
)

VALID_NOTIFICATION_TYPES = {
    'alert',
    'info',
    'warning',
    'error',
    'critical',
    'transactional',
    'promotional',
}

MAX_MESSAGE_LENGTH = 256 * 1024  # SNS max message size is 256 KB
MAX_SUBJECT_LENGTH = 100


def load_config():
    """Load configuration from environment variables."""
    import os

    allowed_arns = os.environ.get('ALLOWED_TOPIC_ARNS', '')
    if allowed_arns:
        for arn in allowed_arns.split(','):
            arn = arn.strip()
            if arn:
                ALLOWED_TOPIC_ARNS.add(arn)

    allowed_accounts = os.environ.get('ALLOWED_AWS_ACCOUNT_IDS', '')
    if allowed_accounts:
        for account_id in allowed_accounts.split(','):
            account_id = account_id.strip()
            if account_id:
                ALLOWED_AWS_ACCOUNT_IDS.add(account_id)

    allowed_regions = os.environ.get('ALLOWED_REGIONS', '')
    if allowed_regions:
        for region in allowed_regions.split(','):
            region = region.strip()
            if region:
                ALLOWED_REGIONS.add(region)

    global ALLOWED_TOPIC_ARN_PATTERN
    pattern = os.environ.get('ALLOWED_TOPIC_ARN_PATTERN', '')
    if pattern:
        try:
            ALLOWED_TOPIC_ARN_PATTERN = re.compile(pattern)
        except re.error:
            logger.error("Invalid ALLOWED_TOPIC_ARN_PATTERN, ignoring")


load_config()


def validate_topic_arn(topic_arn):
    """Validate that the topic ARN is well-formed and in the allowlist."""
    if not isinstance(topic_arn, str):
        raise ValueError("Topic ARN must be a string")

    if not SNS_ARN_PATTERN.match(topic_arn):
        raise ValueError("Topic ARN format is invalid")

    # Extract account ID and region from ARN
    arn_parts = topic_arn.split(':')
    if len(arn_parts) != 6:
        raise ValueError("Topic ARN structure is invalid")

    region = arn_parts[3]
    account_id = arn_parts[4]

    # Validate against allowed account IDs if configured
    if ALLOWED_AWS_ACCOUNT_IDS and account_id not in ALLOWED_AWS_ACCOUNT_IDS:
        raise ValueError(
            f"Topic ARN references unauthorized AWS account"
        )

    # Validate against allowed regions if configured
    if ALLOWED_REGIONS and region not in ALLOWED_REGIONS:
        raise ValueError(
            f"Topic ARN references unauthorized region"
        )

    # Check explicit allowlist
    if ALLOWED_TOPIC_ARNS and topic_arn in ALLOWED_TOPIC_ARNS:
        return True

    # Check pattern-based allowlist
    if ALLOWED_TOPIC_ARN_PATTERN and ALLOWED_TOPIC_ARN_PATTERN.match(topic_arn):
        return True

    # If no allowlists are configured at all, deny by default
    if not ALLOWED_TOPIC_ARNS and ALLOWED_TOPIC_ARN_PATTERN is None:
        raise ValueError(
            "No topic ARN allowlist configured. "
            "Set ALLOWED_TOPIC_ARNS or ALLOWED_TOPIC_ARN_PATTERN environment variables."
        )

    raise ValueError("Topic ARN is not in the allowed list")


def validate_notification_type(notification_type):
    """Validate the notification type against the allowlist."""
    if not isinstance(notification_type, str):
        raise ValueError("Notification type must be a string")

    notification_type = notification_type.lower().strip()

    if notification_type not in VALID_NOTIFICATION_TYPES:
        raise ValueError(
            f"Invalid notification type. Must be one of: {', '.join(sorted(VALID_NOTIFICATION_TYPES))}"
        )

    return notification_type


def sanitize_message(message):
    """Validate and sanitize the message content."""
    if not isinstance(message, str):
        raise ValueError("Message must be a string")

    message = message.strip()

    if not message:
        raise ValueError("Message cannot be empty")

    if len(message.encode('utf-8')) > MAX_MESSAGE_LENGTH:
        raise ValueError(
            f"Message exceeds maximum length of {MAX_MESSAGE_LENGTH} bytes"
        )

    return message


def sanitize_subject(subject):
    """Validate and sanitize the subject line."""
    if subject is None:
        return None

    if not isinstance(subject, str):
        raise ValueError("Subject must be a string")

    subject = subject.strip()

    if not subject:
        return None

    if len(subject) > MAX_SUBJECT_LENGTH:
        raise ValueError(
            f"Subject exceeds maximum length of {MAX_SUBJECT_LENGTH} characters"
        )

    # SNS subjects must not start or end with whitespace and must be ASCII printable
    # Remove any control characters
    subject = ''.join(c for c in subject if c.isprintable())

    if not subject:
        raise ValueError("Subject contains no printable characters")

    return subject


def sanitize_message_attributes(attributes):
    """Validate and sanitize message attributes."""
    if attributes is None:
        return {}

    if not isinstance(attributes, dict):
        raise ValueError("Message attributes must be a dictionary")

    # Limit number of attributes (SNS allows max 10)
    if len(attributes) > 10:
        raise ValueError("Maximum of 10 message attributes allowed")

    sanitized = {}
    for key, value in attributes.items():
        if not isinstance(key, str):
            raise ValueError("Attribute keys must be strings")

        # Validate key format
        if not re.match(r'^[a-zA-Z0-9._-]+$', key):
            raise ValueError(
                f"Invalid attribute key format: keys must contain only "
                f"alphanumeric characters, dots, hyphens, and underscores"
            )

        if len(key) > 256:
            raise ValueError("Attribute key exceeds maximum length of 256")

        if not isinstance(value, dict):
            raise ValueError("Attribute values must be dictionaries with DataType and StringValue")

        data_type = value.get('DataType', '')
        if data_type not in ('String', 'Number', 'Binary'):
            raise ValueError(
                f"Invalid DataType for attribute '{key}'. Must be String, Number, or Binary"
            )

        sanitized_value = {'DataType': data_type}

        if data_type in ('String', 'Number'):
            string_value = value.get('StringValue', '')
            if not isinstance(string_value, str):
                raise ValueError(f"StringValue for attribute '{key}' must be a string")
            if len(string_value) > 256:
                raise ValueError(
                    f"StringValue for attribute '{key}' exceeds maximum length"
                )
            sanitized_value['StringValue'] = string_value
        elif data_type == 'Binary':
            binary_value = value.get('BinaryValue', b'')
            if not isinstance(binary_value, (bytes, bytearray)):
                raise ValueError(f"BinaryValue for attribute '{key}' must be bytes")
            sanitized_value['BinaryValue'] = binary_value

        sanitized[key] = sanitized_value

    return sanitized


def build_message_for_type(notification_type, message, metadata=None):
    """Build a structured message based on notification type."""
    import datetime

    structured_message = {
        'notification_type': notification_type,
        'message': message,
        'timestamp': datetime.datetime.utcnow().isoformat() + 'Z',
        'version': '1.0',
    }

    if metadata and isinstance(metadata, dict):
        # Only include safe metadata keys
        safe_keys = {'source', 'correlation_id', 'priority', 'category', 'tags'}
        safe_metadata = {}
        for key in safe_keys:
            if key in metadata:
                value = metadata[key]
                if isinstance(value, (str, int, float, bool, list)):
                    safe_metadata[key] = value
        if safe_metadata:
            structured_message['metadata'] = safe_metadata

    return json.dumps(structured_message, default=str)


def get_subject_for_type(notification_type, custom_subject=None):
    """Generate an appropriate subject line based on notification type."""
    if custom_subject:
        return custom_subject

    subject_map = {
        'alert': '[ALERT] Event Notification',
        'info': '[INFO] Event Notification',
        'warning': '[WARNING] Event Notification',
        'error': '[ERROR] Event Notification',
        'critical': '[CRITICAL] Event Notification',
        'transactional': '[TRANSACTION] Event Notification',
        'promotional': '[UPDATE] Event Notification',
    }

    return subject_map.get(notification_type, '[NOTIFICATION] Event Notification')


def publish_message(sns_client, topic_arn, message, subject=None, message_attributes=None):
    """Publish a message to the specified SNS topic."""
    publish_params = {
        'TopicArn': topic_arn,
        'Message': message,
    }

    if subject:
        publish_params['Subject'] = subject

    if message_attributes:
        publish_params['MessageAttributes'] = message_attributes

    try:
        response = sns_client.publish(**publish_params)
        message_id = response.get('MessageId', 'unknown')
        # Log without including message content to avoid leaking sensitive data
        logger.info(
            "Message published successfully. MessageId: %s, TopicArn: %s",
            message_id,
            topic_arn
        )
        return {
            'message_id': message_id,
            'status': 'success',
        }
    except ClientError as e:
        error_code = e.response['Error']['Code']
        # Log error without sensitive details
        logger.error(
            "Failed to publish message. ErrorCode: %s, TopicArn: %s",
            error_code,
            topic_arn
        )
        raise


def lambda_handler(event, context):
    """
    Lambda handler for publishing messages to SNS topics.

    Expected event structure:
    {
        "topic_arn": "arn:aws:sns:us-east-1:123456789012:MyTopic",
        "notification_type": "alert",
        "message": "Your notification message here",
        "subject": "Optional subject line",
        "metadata": {
            "source": "my-service",
            "correlation_id": "abc-123",
            "priority": "high"
        },
        "message_attributes": {
            "AttributeName": {
                "DataType": "String",
                "StringValue": "AttributeValue"
            }
        }
    }

    For batch publishing:
    {
        "batch": true,
        "notifications": [
            {
                "topic_arn": "...",
                "notification_type": "...",
                "message": "..."
            }
        ]
    }
    """
    try:
        if not isinstance(event, dict):
            return {
                'statusCode': 400,
                'body': json.dumps({
                    'error': 'Invalid event format',
                    'status': 'failed',
                }),
            }

        sns_client = boto3.client('sns')

        # Handle batch notifications
        is_batch = event.get('batch', False)
        if is_batch:
            return handle_batch_notifications(sns_client, event)

        # Handle single notification
        return handle_single_notification(sns_client, event)

    except ValueError as e:
        logger.warning("Validation error: %s", str(e))
        return {
            'statusCode': 400,
            'body': json.dumps({
                'error': str(e),
                'status': 'failed',
            }),
        }
    except ClientError as e:
        error_code = e.response['Error']['Code']
        if error_code == 'AuthorizationError':
            return {
                'statusCode': 403,
                'body': json.dumps({
                    'error': 'Not authorized to publish to this topic',
                    'status': 'failed',
                }),
            }
        elif error_code == 'NotFoundException':
            return {
                'statusCode': 404,
                'body': json.dumps({
                    'error': 'SNS topic not found',
                    'status': 'failed',
                }),
            }
        else:
            logger.error("SNS ClientError: %s", error_code)
            return {
                'statusCode': 500,
                'body': json.dumps({
                    'error': 'Failed to publish message',
                    'status': 'failed',
                }),
            }
    except Exception:
        logger.exception("Unexpected error in lambda_handler")
        return {
            'statusCode': 500,
            'body': json.dumps({
                'error': 'Internal server error',
                'status': 'failed',
            }),
        }


def handle_single_notification(sns_client, event):
    """Handle publishing a single notification."""
    # Extract and validate inputs
    topic_arn = event.get('topic_arn')
    if not topic_arn:
        raise ValueError("topic_arn is required")

    validate_topic_arn(topic_arn)

    notification_type = event.get('notification_type')
    if not notification_type:
        raise ValueError("notification_type is required")

    notification_type = validate_notification_type(notification_type)

    message = event.get('message')
    if not message:
        raise ValueError("message is required")

    message = sanitize_message(message)

    custom_subject = event.get('subject')
    if custom_subject:
        custom_subject = sanitize_subject(custom_subject)

    metadata = event.get('metadata')
    message_attributes = sanitize_message_attributes(
        event.get('message_attributes')
    )

    # Add notification type as a message attribute for filtering
    message_attributes['notification_type'] = {
        'DataType': 'String',
        'StringValue': notification_type,
    }

    # Build structured message
    structured_message = build_message_for_type(
        notification_type, message, metadata
    )

    # Generate subject
    subject = get_subject_for_type(notification_type, custom_subject)

    # Publish
    result = publish_message(
        sns_client,
        topic_arn,
        structured_message,
        subject=subject,
        message_attributes=message_attributes,
    )

    return {
        'statusCode': 200,
        'body': json.dumps({
            'message_id': result['message_id'],
            'notification_type': notification_type,
            'status': 'success',
        }),
    }


def handle_batch_notifications(sns_client, event):
    """Handle publishing multiple notifications."""
    notifications = event.get('notifications', [])

    if not isinstance(notifications, list):
        raise ValueError("notifications must be a list")

    # Limit batch size to prevent abuse
    max_batch_size = 25
    if len(notifications) > max_batch_size:
        raise ValueError(
            f"Batch size exceeds maximum of {max_batch_size} notifications"
        )

    if len(notifications) == 0:
        raise ValueError("At least one notification is required")

    results = []
    errors = []

    for i, notification in enumerate(notifications):
        if not isinstance(notification, dict):
            errors.append({
                'index': i,
                'error': 'Notification must be a dictionary',
            })
            continue

        try:
            result = handle_single_notification(sns_client, notification)
            result_body = json.loads(result['body'])
            results.append({
                'index': i,
                'message_id': result_body.get('message_id'),
                'status': 'success',
            })
        except (ValueError, ClientError) as e:
            error_msg = str(e) if isinstance(e, ValueError) else e.response['Error']['Code']
            logger.warning("Batch item %d failed: %s", i, error_msg)
            errors.append({
                'index': i,
                'error': error_msg,
                'status': 'failed',
            })

    status_code = 200 if not errors else (207 if results else 400)

    return {
        'statusCode': status_code,
        'body': json.dumps({
            'total': len(notifications),
            'successful': len(results),
            'failed': len(errors),
            'results': results,
            'errors': errors,
            'status': 'completed',
        }),
    }